<template>
  <div class="mv-container">
    <div class="mv-wrap">
      <h3 class="title">mv详情</h3>
      <!-- mv -->
      <div class="video-wrap">
        <video autoplay controls :src="url"></video>
      </div>
      <!-- mv信息 -->
      <div class="info-wrap">
        <div class="singer-info">
          <div class="avatar-wrap">
            <img :src="singer.picUrl" alt="" />
          </div>
          <span class="name">{{mvInfo.artistName}}</span>
        </div>
        <div class="mv-info">
          <h2 class="title">{{mvInfo.name}}</h2>
          <span class="date">发布：{{mvInfo.publishTime}}</span>
          <span class="number">播放：{{mvInfo.playCount|getCount}}次</span>
          <p class="desc">
            {{mvInfo.desc}}
          </p>
        </div>
      </div>
      <!-- 精彩评论 -->
      <div class="comment-wrap">
        <p class="title">精彩评论<span class="number">({{hotComment.length}})</span></p>
        <div class="comments-wrap">
          <div class="item" v-for="(item,i) in hotComment" :key="i">
            <div class="icon-wrap">
              <img :src="item.user.avatarUrl" alt="" />
            </div>
            <div class="content-wrap">
              <div class="content" >
                <span class="name">{{item.user.nickname}}：</span>
                <span class="comment">{{item.content}}</span>
              </div>
              <div class="re-content" v-if="item.beReplied.length>0">
                <span class="name">{{item.beReplied[0].user.nickname}}：</span>
                <span class="comment">{{item.beReplied[0].content}}</span>
              </div>
              <div class="date">
                <div>{{item.time|filterDate2}}</div>
                <div class="dzinfo">
                  <span class="iconfont icon-dianzan1"></span>
                  <span class="dz">({{item.likedCount}})</span>
                </div>
              </div>
            </div>
          </div>
        </div>
      </div>
      <!-- 最新评论 -->
      <div class="comment-wrap">
        <p class="title">最新评论<span class="number">({{comment.length}})</span></p>
        <div class="comments-wrap">
          <div class="item" v-for="(item,i) in comment" :key="i">
            <div class="icon-wrap">
              <img :src="item.user.avatarUrl" alt="" />
            </div>
            <div class="content-wrap">
              <div class="content">
                <span class="name">{{item.user.nickname}}：</span>
                <span class="comment">{{item.content}}</span>
              </div>
              <div class="re-content" v-if="item.beReplied.length>0">
                <span class="name">{{item.beReplied[0].user.nickname}}：</span>
                <span class="comment">{{item.beReplied[0].content}}</span>
              </div>
               <div class="date">
                <div>{{item.time|filterDate}}</div>
                <div class="dzinfo">
                  <span class="iconfont icon-dianzan1"></span>
                  <span class="dz">({{item.likedCount}})</span>
                </div>
              </div>
            </div>
          </div>
        </div>
      </div>
      <!-- 分页器 -->
      <el-pagination
        @current-change="handleCurrentChange"
        background
        layout="prev, pager, next"
        :total="total"
        :current-page="page"
        :page-size="5"
        :limit="10"
      >
      </el-pagination>
    </div>
    <div class="mv-recommend">
      <h3 class="title">相关推荐</h3>
      <div class="mvs">
        <div class="items">
          <div class="item" v-for="(item,i) in mvs" :key="i" @click="relaMv(item.id)">
            <div class="img-wrap">
              <img :src="item.cover" alt="" />
              <span class="iconfont icon-icon_play_default"></span>
              <div class="num-wrap">
                <div class="iconfont icon-icon_play_default"></div>
                <div class="num">{{item.playCount|getCount}}</div>
              </div>
              <span class="time">{{item.duration|getGapTime}}</span>
            </div>
            <div class="info-wrap">
              <div class="name">{{item.name}}</div>
              <div class="singer">{{item.artistName}}</div>
            </div>
          </div>
        </div>
      </div>
    </div>
  </div>
</template>

<script>
import music from "@/api/music";
import moment from "moment"
export default {
  name: "mv",
  data() {
    return {
      // 总条数
      total: 20,
      // 页码
      page: 1,
      url: "",
      id:this.$route.query.id,
      mvs:[],
      mvInfo:{},
      singer:{},
      comment:[],
      hotComment:[]
    };
  },
  watch:{
    id(){
      this.goMvDetail();
    this.goRelationMv();
    this.goMvInfo();
    this.goCommentInfo()
    }
  },
  methods: {
    relaMv(id){
      this.id = id
    },
    handleCurrentChange(val) {
      this.page = val
      this.goCommentInfo()
    },
    async goMvDetail() {
      const res = await music.mvDetail({
        params: {
          id: this.id,
        },
      });
      this.url = res.data.url;
    },
    // 相关mv
    async goRelationMv(){
      const res = await music.mvRelation({
         params: {
          mvid: this.id,
        },
      })
      this.mvs = res.mvs
    },
    async goMvInfo(){
      const res = await music.mvInfo({
         params: {
          mvid: this.id,
        },
      })
      this.mvInfo = res.data
      this.goSingerInfo(res.data.artistId)
    },
    // 歌手信息
    async goSingerInfo(artistId){
      const res = await music.singerInfo({
        params:{
          id:artistId
        }
      })
      this.singer = res.artist
    },
    // 评论信息
    async goCommentInfo(){
      const res = await music.commentInfo({
        params:{
          id:this.id,
          limit:10,
          offset:(this.page-1)*10
        }
      })
      this.hotComment = res.hotComments
      this.comment = res.comments
      this.total = res.total
    }
  },
  created() {
    // console.log(this.$route.query.id)
    this.goMvDetail();
    this.goRelationMv();
    this.goMvInfo();
    this.goCommentInfo()
  },
};
</script>

<style lang="scss">
.mv-container{
  .mv-wrap{
    margin-right: 0;
  }
  .video-wrap{
    video{
      object-fit:fill;
    }
  }
  .re-content2{
    background: none!important;
  }
  .date{
    display: flex;
    justify-content: space-between;
    align-items: center;
    .dzinfo{
      display: flex;
      align-items: center;
    }
    .icon-dianzan1{
      color: #FF962F;
      font-size: 20px;
      margin-right: 5px;
    }
    .dz{
      color: black;
    }
  }
}
</style>
